export interface AnalysisResult {
  id: string;
  imageUrl: string;
  name: string;
  score: number; // 1-10
  isAiGenerated: boolean;
  confidence: number;
  reasoning: string;
  technicalDetails: string[];
  timestamp: number;
}

export interface LeaderboardEntry {
  id: string;
  username: string;
  points: number;
  avatar: string;
}

export interface GeminiResponse {
  score: number;
  isAiGenerated: boolean;
  confidence: number;
  reasoning: string;
  technicalDetails: string[];
}

import { GoogleGenAI, Type } from "@google/genai";
import { GeminiResponse } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

export const analyzeImage = async (base64Image: string, mimeType: string): Promise<GeminiResponse> => {
  const model = 'gemini-3-flash-preview';

  const systemInstruction = `
    You are a world-class forensic digital art analyst at "PYTHENIANS LABO".
    Your task is to analyze the provided image and determine if it is "AI Slop" (generic, low-effort AI generation) or a high-quality "Human/Professional Design".

    Criteria for Low Score (AI Slop):
    - Nonsensical anatomical details (fingers, limbs).
    - Unnatural "AI lighting" or over-polished, plasticky skin.
    - Hallucinated text or gibberish characters.
    - Artifacts in complex patterns (checkerboards, lace).
    - Lack of artistic intent or soul.

    Criteria for High Score (10/10):
    - High technical execution (perfect perspective, consistent lighting).
    - Deliberate artistic choices.
    - Clean typography and logical design layout.
    - Complexity that suggests human software usage (layers, brushes, intentional noise).

    Rate from 1 to 10:
    - 1: Obvious, low-quality AI slop.
    - 10: Masterpiece human design/art.
  `;

  const response = await ai.models.generateContent({
    model,
    contents: {
      parts: [
        {
          inlineData: {
            mimeType,
            data: base64Image.split(',')[1],
          },
        },
        {
          text: "Analyze this image. Provide the result in JSON format."
        },
      ],
    },
    config: {
      systemInstruction,
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          score: { type: Type.NUMBER, description: "Rating from 1-10" },
          isAiGenerated: { type: Type.BOOLEAN, description: "Whether it was likely generated by AI" },
          confidence: { type: Type.NUMBER, description: "Confidence percentage 0-100" },
          reasoning: { type: Type.STRING, description: "Brief explanation of the rating" },
          technicalDetails: { 
            type: Type.ARRAY, 
            items: { type: Type.STRING },
            description: "List of specific forensic details found (e.g., 'mangled fingers', 'consistent lighting')"
          },
        },
        required: ["score", "isAiGenerated", "confidence", "reasoning", "technicalDetails"],
      },
    },
  });

  return JSON.parse(response.text) as GeminiResponse;
};

import React, { useState, useEffect, useCallback } from 'react';
import { Upload, Trophy, Zap, AlertCircle, RefreshCw, BarChart3, Fingerprint, Image as ImageIcon } from 'lucide-react';
import { AnalysisResult, LeaderboardEntry } from './types';
import { analyzeImage } from './services/geminiService';

// --- Components ---

const Header = () => (
  <header className="py-8 text-center">
    <h1 className="text-5xl font-black font-orbitron tracking-tighter text-transparent bg-clip-text bg-gradient-to-r from-purple-400 via-fuchsia-500 to-indigo-500 mb-2">
      PYTHENIANS LABO
    </h1>
    <p className="text-purple-300/70 font-medium tracking-widest uppercase text-sm">
      Forensic AI Slop Detection Protocol
    </p>
  </header>
);

const SlopMeter = ({ score }: { score: number }) => {
  const percentage = (score / 10) * 100;
  const getColor = () => {
    if (score >= 8) return 'bg-green-500 shadow-[0_0_15px_rgba(34,197,94,0.5)]';
    if (score >= 5) return 'bg-yellow-500 shadow-[0_0_15px_rgba(234,179,8,0.5)]';
    return 'bg-red-500 shadow-[0_0_15px_rgba(239,68,68,0.5)]';
  };

  return (
    <div className="w-full">
      <div className="flex justify-between items-center mb-1 text-xs font-bold uppercase tracking-wider">
        <span className="text-purple-300">Human Craft</span>
        <span className="text-purple-100 text-lg font-orbitron">{score}/10</span>
      </div>
      <div className="h-3 w-full bg-purple-900/30 rounded-full overflow-hidden border border-purple-500/20">
        <div 
          className={`h-full transition-all duration-1000 ease-out ${getColor()}`}
          style={{ width: `${percentage}%` }}
        />
      </div>
    </div>
  );
};

const Leaderboard = ({ entries }: { entries: LeaderboardEntry[] }) => (
  <div className="bg-glass rounded-3xl p-6 h-full">
    <div className="flex items-center gap-3 mb-6">
      <Trophy className="text-yellow-400 w-6 h-6" />
      <h2 className="text-xl font-bold font-orbitron">Pyth Points Race</h2>
