const AnalysisCard = ({ result, onDelete }: { result: AnalysisResult; onDelete: (id: string) => void }) => (
  <div className="bg-glass rounded-3xl overflow-hidden group hover:purple-glow transition-all duration-300 flex flex-col">
    <div className="relative h-64 overflow-hidden">
      <img src={result.imageUrl} alt={result.name} className="w-full h-full object-cover transition-transform duration-700 group-hover:scale-110" />
      <div className="absolute top-4 left-4">
        <div className={`px-3 py-1 rounded-full text-[10px] font-black uppercase tracking-widest backdrop-blur-md ${result.isAiGenerated ? 'bg-red-500/80 text-white' : 'bg-green-500/80 text-white'}`}>
          {result.isAiGenerated ? 'AI Detected' : 'Human Made'}
        </div>
      </div>
      <button 
        onClick={() => onDelete(result.id)}
        className="absolute top-4 right-4 p-2 rounded-full bg-black/50 hover:bg-red-500 transition-colors opacity-0 group-hover:opacity-100"
      >
        <Zap className="w-4 h-4 text-white" />
