      <div className="mb-6">
        <SlopMeter score={result.score} />
      </div>

      <div className="flex-1">
        <h4 className="text-xs font-bold uppercase text-purple-400 mb-2 flex items-center gap-2">
          <AlertCircle className="w-3 h-3" /> Lab Reasoning
        </h4>
        <p className="text-sm text-purple-100/80 leading-relaxed mb-4">
          {result.reasoning}
        </p>

        <div className="flex flex-wrap gap-2">
          {result.technicalDetails.map((detail, i) => (
            <span key={i} className="text-[10px] bg-purple-500/10 border border-purple-500/20 px-2 py-1 rounded-md text-purple-300 uppercase font-bold">
              {detail}
            </span>
          ))}
        </div>
      </div>

