);

// --- Main App ---

export default function App() {
  const [isAnalyzing, setIsAnalyzing] = useState(false);
  const [results, setResults] = useState<AnalysisResult[]>([]);
  const [error, setError] = useState<string | null>(null);

  // Mock Leaderboard Data
  const [leaderboard] = useState<LeaderboardEntry[]>([
    { id: '1', username: 'CryptoVinci', points: 4520, avatar: 'https://picsum.photos/seed/1/100' },
    { id: '2', username: 'PixelSlayer', points: 3890, avatar: 'https://picsum.photos/seed/2/100' },
    { id: '3', username: 'DesignGod', points: 3750, avatar: 'https://picsum.photos/seed/3/100' },
    { id: '4', username: 'PythMaster', points: 2100, avatar: 'https://picsum.photos/seed/4/100' },
    { id: '5', username: 'SlopHunter', points: 1850, avatar: 'https://picsum.photos/seed/5/100' },
  ]);

  const handleFileUpload = async (event: React.ChangeEvent<HTMLInputElement>) => {
    const files = event.target.files;
    if (!files || files.length === 0) return;

    setIsAnalyzing(true);
    setError(null);

    try {
      const fileArray = Array.from(files);

      for (const file of fileArray) {
        const reader = new FileReader();
        const base64Promise = new Promise<string>((resolve) => {
          reader.onload = (e) => resolve(e.target?.result as string);
        });
        reader.readAsDataURL(file);
        const base64Data = await base64Promise;

        const analysis = await analyzeImage(base64Data, file.type);

        const newResult: AnalysisResult = {
          id: Math.random().toString(36).substr(2, 9),
          imageUrl: base64Data,
          name: file.name,
          score: analysis.score,
          isAiGenerated: analysis.isAiGenerated,
          confidence: analysis.confidence,
          reasoning: analysis.reasoning,
          technicalDetails: analysis.technicalDetails,
          timestamp: Date.now(),
        };

        setResults(prev => [newResult, ...prev]);
      }
    } catch (err) {
      console.error(err);
      setError("System failure during forensic analysis. Please recalibrate.");
    } finally {
      setIsAnalyzing(false);
    }
  };

  const deleteResult = (id: string) => {
    setResults(prev => prev.filter(r => r.id !== id));
  };

  return (
    <div className="min-h-screen p-4 md:p-8 max-w-[1600px] mx-auto">
      <Header />

      <main className="grid grid-cols-1 lg:grid-cols-12 gap-8">
        {/* Left Column: Analysis Results */}
        <div className="lg:col-span-8 space-y-8">

          {/* Upload Area */}
          <div className="relative group">
            <div className="absolute -inset-1 bg-gradient-to-r from-purple-600 to-fuchsia-600 rounded-3xl blur opacity-25 group-hover:opacity-50 transition duration-1000 group-hover:duration-200"></div>
            <div className="relative bg-glass rounded-3xl p-10 flex flex-col items-center justify-center border-2 border-dashed border-purple-500/30 hover:border-purple-500/60 transition-all cursor-pointer">
              <input 
                type="file" 
                multiple 
                accept="image/*" 
                onChange={handleFileUpload}
                className="absolute inset-0 opacity-0 cursor-pointer"
                disabled={isAnalyzing}
              />
              <div className="bg-purple-600/20 p-6 rounded-full mb-6 group-hover:scale-110 transition-transform duration-500">
                {isAnalyzing ? (
                  <RefreshCw className="w-12 h-12 text-purple-400 animate-spin" />
                ) : (
                  <Upload className="w-12 h-12 text-purple-400" />
                )}
              </div>
              <h2 className="text-2xl font-bold font-orbitron mb-2">Initialize Scanning</h2>
              <p className="text-purple-300/60 text-center max-w-sm mb-6 uppercase tracking-wider text-xs font-bold">
                Drop your digital artifacts here for authenticity verification
              </p>

              {isAnalyzing && (
                <div className="flex items-center gap-3 py-2 px-4 bg-purple-500/10 rounded-full animate-pulse border border-purple-500/20">
                  <BarChart3 className="w-4 h-4 text-fuchsia-400" />
                  <span className="text-xs font-black text-fuchsia-400 uppercase tracking-tighter">Running Neural Forensic Protocols...</span>
                </div>
              )}

              {error && (
                <div className="mt-4 flex items-center gap-2 text-red-400 bg-red-400/10 px-4 py-2 rounded-xl border border-red-400/20">
                  <AlertCircle className="w-4 h-4" />
                  <span className="text-xs font-bold">{error}</span>
                </div>
              )}
            </div>
          </div>

          {/* Results Grid */}
          <div className="space-y-6">
            <div className="flex items-center justify-between px-2">
              <h2 className="text-2xl font-bold font-orbitron flex items-center gap-3">
                <BarChart3 className="text-purple-400" />
                Latest Scans
              </h2>
              <div className="text-xs font-black uppercase tracking-widest text-purple-500">
                {results.length} Entities Evaluated
              </div>
            </div>

            {results.length === 0 ? (
              <div className="bg-glass rounded-3xl p-20 flex flex-col items-center justify-center text-center">
                <ImageIcon className="w-16 h-16 text-purple-900 mb-4" />
                <p className="text-purple-500 font-bold uppercase tracking-widest text-sm">Waiting for Neural Feed...</p>
              </div>
            ) : (
              <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                {results.map((result) => (
                  <AnalysisCard key={result.id} result={result} onDelete={deleteResult} />
                ))}
              </div>
            )}
          </div>
        </div>

        {/* Right Column: Leaderboard & Stats */}
        <div className="lg:col-span-4 space-y-8">
          <Leaderboard entries={leaderboard} />

          <div className="bg-glass rounded-3xl p-8 border border-purple-500/20">
            <h3 className="text-lg font-bold font-orbitron mb-4 flex items-center gap-2">
              <Zap className="text-yellow-400 w-5 h-5" />
              Lab Directive
            </h3>
            <div className="space-y-4 text-sm text-purple-300/80 leading-relaxed">
              <p>
                <span className="text-white font-bold">1. </span> 
                The Lab detects AI hallucinations, plastic shading, and anatomical errors.
              </p>
              <p>
                <span className="text-white font-bold">2. </span> 
                High ratings (8-10) signify elite human craftsmanship and intentionality.
              </p>
              <p>
                <span className="text-white font-bold">3. </span> 
                Low ratings (1-3) identify "AI Slop" — low-effort content used to farm engagement.
              </p>
              <p className="pt-4 border-t border-purple-500/10 text-xs font-medium italic text-purple-400">
                Pythenians Labo is the final authority on digital authenticity.
              </p>
            </div>
          </div>
        </div>
      </main>

      <footer className="mt-20 py-10 border-t border-purple-900/50 text-center">
        <p className="text-purple-500 text-xs font-black uppercase tracking-[0.2em]">
          &copy; 2024 Pythenians Labo // Authenticity Protocol Active
        </p>
      </footer>
    </div>
  );
}

import { GoogleGenAI, Type } from "@google/genai";
import { GeminiResponse } from "../types";

// Always use named parameter for apiKey and directly use process.env.API_KEY
const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

export const analyzeImage = async (base64Image: string, mimeType: string): Promise<GeminiResponse> => {
  const model = 'gemini-3-flash-preview';

  const systemInstruction = `
    You are a world-class forensic digital art analyst at "PYTHENIANS LABO".
    Your task is to analyze the provided image and determine if it is "AI Slop" (generic, low-effort AI generation) or a high-quality "Human/Professional Design".

    Criteria for Low Score (AI Slop):
    - Nonsensical anatomical details (fingers, limbs).
    - Unnatural "AI lighting" or over-polished, plasticky skin.
    - Hallucinated text or gibberish characters.
    - Artifacts in complex patterns (checkerboards, lace).
    - Lack of artistic intent or soul.

    Criteria for High Score (10/10):
    - High technical execution (perfect perspective, consistent lighting).
    - Deliberate artistic choices.
    - Clean typography and logical design layout.
    - Complexity that suggests human software usage (layers, brushes, intentional noise).

    Rate from 1 to 10:
    - 1: Obvious, low-quality AI slop.
    - 10: Masterpiece human design/art.
  `;

  const response = await ai.models.generateContent({
    model,
    contents: {
      parts: [
        {
          inlineData: {
            mimeType,
            data: base64Image.split(',')[1],
          },
        },
        {
          text: "Analyze this image. Provide the result in JSON format."
        },
      ],
    },
    config: {
      systemInstruction,
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          score: { type: Type.NUMBER, description: "Rating from 1-10" },
          isAiGenerated: { type: Type.BOOLEAN, description: "Whether it was likely generated by AI" },
          confidence: { type: Type.NUMBER, description: "Confidence percentage 0-100" },
          reasoning: { type: Type.STRING, description: "Brief explanation of the rating" },
          technicalDetails: { 
            type: Type.ARRAY, 
            items: { type: Type.STRING },
