// --- Helpers ---

/**
 * Generates a unique, stylish avatar URL based on the username.
 * Uses the Dicebear API with the 'notionists' style for a clean, lab-appropriate aesthetic.
 */
const getAvatarUrl = (username: string): string => {
  const seed = encodeURIComponent(username);
  // Using 'notionists' style for a professional yet characterful look that fits the Pythenians vibe
  return `https://api.dicebear.com/9.x/notionists/svg?seed=${seed}&backgroundColor=c0aede,b6e3f4,d1d4f9,ffd5dc,ffdfbf`;
};

/**
 * Extracts participant names from image filenames.
 */
const extractParticipant = (filename: string): string => {
  const nameWithoutExt = filename.replace(/\.[^/.]+$/, "");
  const parts = nameWithoutExt.split(/[-_ ]/);

  if (parts.length >= 2) {
    return parts.slice(0, 2).map(p => p.charAt(0).toUpperCase() + p.slice(1)).join(" ");
  }
  return parts[0].charAt(0).toUpperCase() + parts[0].slice(1);
};

