const SlopMeter = ({ score }: { score: number }) => {
  const percentage = (score / 10) * 100;
  const getColor = () => {
    if (score >= 8) return 'bg-green-500 shadow-[0_0_15px_rgba(34,197,94,0.5)]';
    if (score >= 5) return 'bg-yellow-500 shadow-[0_0_15px_rgba(234,179,8,0.5)]';
    return 'bg-red-500 shadow-[0_0_15px_rgba(239,68,68,0.5)]';
  };

  return (
    <div className="w-full">
      <div className="flex justify-between items-center mb-1 text-xs font-bold uppercase tracking-wider">
        <span className="text-purple-300">Human Craft</span>
        <span className="text-purple-100 text-lg font-orbitron">{score}/10</span>
      </div>
      <div className="h-3 w-full bg-purple-900/30 rounded-full overflow-hidden border border-purple-500/20">
        <div 
          className={`h-full transition-all duration-1000 ease-out ${getColor()}`}
          style={{ width: `${percentage}%` }}
        />
      </div>
    </div>
  );
};

