                  <div className="space-y-3">
                    {leaderboard.slice(3).map((entry, i) => (
                      <div key={entry.id} className="flex items-center justify-between p-2 rounded-xl bg-purple-900/10 border border-purple-500/5 group hover:border-purple-500/30 transition-all">
