                        </div>
                        <span className="text-[10px] font-orbitron text-fuchsia-400">{entry.points.toLocaleString()}</span>
                      </div>
                    ))}
                  </div>
                </div>
              )}
            </div>
          </div>

          <div className="lg:col-span-8 space-y-6">
            <div className="flex flex-col md:flex-row md:items-center justify-between gap-4 px-2">
              <div className="flex items-center gap-3">
                <Fingerprint className="text-purple-400" />
                <h2 className="text-2xl font-black font-orbitron text-purple-100">Forensic Feed</h2>
