export default function App() {
  const [isAnalyzing, setIsAnalyzing] = useState(false);
  const [results, setResults] = useState<AnalysisResult[]>([]);
  const [error, setError] = useState<string | null>(null);
  const [prizePool, setPrizePool] = useState<number>(10000);
  const [activeFilter, setActiveFilter] = useState<string | null>(null);

  // Extract all unique technical details across all results for filtering
  const allTechnicalDetails = useMemo(() => {
    const details = new Set<string>();
    results.forEach(res => res.technicalDetails.forEach(d => details.add(d)));
    return Array.from(details).sort();
  }, [results]);

  // Derived filtered results
  const filteredResults = useMemo(() => {
    if (!activeFilter) return results;
    return results.filter(res => res.technicalDetails.includes(activeFilter));
  }, [results, activeFilter]);

  // Derive dynamic leaderboard from live results
  const leaderboard = useMemo(() => {
    const userScores: Record<string, { total: number; count: number; best: number }> = {};

    results.forEach(res => {
      const username = extractParticipant(res.name);
      if (!userScores[username]) {
        userScores[username] = { total: 0, count: 0, best: 0 };
      }
      userScores[username].total += res.score;
      userScores[username].count += 1;
      userScores[username].best = Math.max(userScores[username].best, res.score);
    });

    return Object.entries(userScores)
      .map(([username, stats]) => ({
        id: username,
        username,
        points: Math.floor(stats.best * 1000 + stats.total * 50),
        avatar: getAvatarUrl(username)
      }))
      .sort((a, b) => b.points - a.points)
      .slice(0, 10);
  }, [results]);

  const handleFileUpload = async (event: React.ChangeEvent<HTMLInputElement>) => {
    const files = event.target.files;
    if (!files || files.length === 0) return;

    setIsAnalyzing(true);
    setError(null);

    try {
      const fileArray: File[] = Array.from(files);

      for (const file of fileArray) {
        const reader = new FileReader();
        const base64Promise = new Promise<string>((resolve) => {
          reader.onload = (e) => resolve(e.target?.result as string);
        });
        reader.readAsDataURL(file);
        const base64Data = await base64Promise;

        const analysis = await analyzeImage(base64Data, file.type);

        const newResult: AnalysisResult = {
          id: Math.random().toString(36).substr(2, 9),
          imageUrl: base64Data,
          name: file.name,
          score: analysis.score,
          isAiGenerated: analysis.isAiGenerated,
          confidence: analysis.confidence,
          reasoning: analysis.reasoning,
          technicalDetails: analysis.technicalDetails,
          timestamp: Date.now(),
        };

        setResults(prev => [newResult, ...prev]);
      }
    } catch (err) {
      console.error(err);
      setError("System failure during forensic analysis. Please recalibrate.");
    } finally {
      setIsAnalyzing(false);
    }
  };

  const deleteResult = (id: string) => {
    setResults(prev => prev.filter(r => r.id !== id));
  };

  return (
    <div className="min-h-screen p-4 md:p-8 max-w-[1400px] mx-auto">
      <Header />

      <main className="space-y-8">

        {/* Prize Pool & Podium Section */}
        <div className="grid grid-cols-1 lg:grid-cols-12 gap-8">
          <div className="lg:col-span-5">
            <PrizePoolConfig pool={prizePool} setPool={setPrizePool} />

            <div className="bg-glass rounded-3xl p-8 border border-purple-500/20 h-fit">
              <h3 className="text-lg font-bold font-orbitron mb-4 flex items-center gap-2">
                <Zap className="text-yellow-400 w-5 h-5" />
                Lab Directive
              </h3>
              <div className="space-y-4 text-sm text-purple-300/80 leading-relaxed font-medium">
                <p>
                  <span className="text-white font-black">Identity: </span> 
                  Artists are verified via warrior-avatar signatures linked to filenames.
                </p>
                <p>
                  <span className="text-white font-black">Protocol: </span> 
                  1-3 = Slop (AI Synthetic). 8-10 = Craft (Intentional Design).
                </p>
                <p>
                  <span className="text-white font-black">Points: </span> 
                  Elite Pyth Points are awarded for high-intent masterpieces. Climb the triad to claim the pool.
                </p>
              </div>
            </div>
          </div>

          <div className="lg:col-span-7">
            {leaderboard.length > 0 ? (
              <Podium winners={leaderboard} pool={prizePool} />
            ) : (
              <div className="bg-glass rounded-3xl p-20 flex flex-col items-center justify-center text-center border-2 border-dashed border-purple-900/30 h-[480px]">
                <Trophy className="w-16 h-16 text-purple-900 mb-6 opacity-30" />
                <h3 className="text-xl font-orbitron text-purple-500 mb-2">Winners Circle Pending</h3>
                <p className="text-purple-600 text-sm max-w-xs font-bold uppercase tracking-widest">Awaiting forensic data submission from participants...</p>
              </div>
            )}
          </div>
        </div>

        {/* Upload & Results Section */}
        <div className="grid grid-cols-1 lg:grid-cols-12 gap-8">

          <div className="lg:col-span-4">
            <div className="sticky top-8 space-y-8">
              <div className="relative group">
                <div className="absolute -inset-1 bg-gradient-to-r from-purple-600 to-fuchsia-600 rounded-3xl blur opacity-25 group-hover:opacity-50 transition duration-1000"></div>
                <div className="relative bg-glass rounded-3xl p-10 flex flex-col items-center justify-center border-2 border-dashed border-purple-500/30 hover:border-purple-500/60 transition-all cursor-pointer">
                  <input 
