                        <div className="flex items-center gap-3">
                          <span className="text-[10px] font-orbitron text-purple-600 w-4 font-black">{i + 4}</span>
                          <img src={entry.avatar} alt={entry.username} className="w-8 h-8 rounded-full border border-purple-500/20 bg-purple-900/20 group-hover:ring-2 ring-purple-500/30 transition-all" />
                          <span className="text-xs font-bold text-purple-100 truncate max-w-[100px]">{entry.username}</span>
                        </div>
                        <span className="text-[10px] font-orbitron font-bold text-fuchsia-400">{entry.points.toLocaleString()}</span>
                      </div>
                    ))}
                  </div>
                </div>
              )}
            </div>
          </div>

          <div className="lg:col-span-8 space-y-6">
            <div className="flex flex-col md:flex-row md:items-center justify-between gap-4 px-2">
              <div className="flex items-center gap-3">
                <Fingerprint className="text-purple-400" />
                <h2 className="text-2xl font-black font-orbitron text-purple-100 tracking-tight">Forensic Feed</h2>
                <div className="text-[10px] font-black uppercase tracking-widest text-purple-500 bg-purple-900/20 px-3 py-1 rounded-full border border-purple-500/10">
                  {results.length} Artifacts Analyzed
                </div>
              </div>

              {results.length > 0 && (
                <div className="flex items-center gap-2">
                  <Filter className="w-4 h-4 text-purple-500" />
                  <span className="text-[10px] font-black uppercase tracking-widest text-purple-500 mr-2">Neural Filter:</span>
                </div>
              )}
            </div>

            {/* Filter Section */}
            {allTechnicalDetails.length > 0 && (
              <div className="flex flex-wrap gap-2 px-2 pb-2">
                <button
                  onClick={() => setActiveFilter(null)}
                  className={`px-3 py-1.5 rounded-full text-[10px] font-black uppercase tracking-widest transition-all border ${
                    activeFilter === null 
                      ? 'bg-purple-600 border-purple-400 text-white shadow-[0_0_10px_rgba(168,85,247,0.4)]' 
                      : 'bg-purple-900/20 border-purple-500/20 text-purple-400 hover:border-purple-500/40'
                  }`}
                >
                  All Protocols
                </button>
                {allTechnicalDetails.map((detail) => (
                  <button
                    key={detail}
                    onClick={() => setActiveFilter(activeFilter === detail ? null : detail)}
                    className={`px-3 py-1.5 rounded-full text-[10px] font-black uppercase tracking-widest transition-all border flex items-center gap-2 ${
                      activeFilter === detail 
                        ? 'bg-fuchsia-600 border-fuchsia-400 text-white shadow-[0_0_10px_rgba(192,38,211,0.4)]' 
                        : 'bg-purple-900/20 border-purple-500/20 text-purple-400 hover:border-purple-500/40'
                    }`}
                  >
                    {detail}
                    {activeFilter === detail && <X className="w-3 h-3" />}
                  </button>
                ))}
              </div>
            )}

            {results.length === 0 ? (
              <div className="bg-glass rounded-3xl p-32 flex flex-col items-center justify-center text-center border border-purple-500/10">
                <ImageIcon className="w-16 h-16 text-purple-900/20 mb-4" />
                <p className="text-purple-700 font-bold uppercase tracking-[0.2em] text-xs">Waiting for artifacts to deploy...</p>
              </div>
            ) : filteredResults.length === 0 ? (
              <div className="bg-glass rounded-3xl p-20 flex flex-col items-center justify-center text-center border border-purple-500/10">
                <Filter className="w-12 h-12 text-purple-900/40 mb-4" />
                <p className="text-purple-500 font-bold uppercase tracking-widest text-sm mb-2">No artifacts match token: "{activeFilter}"</p>
                <button 
                  onClick={() => setActiveFilter(null)}
                  className="text-[10px] font-black text-fuchsia-400 uppercase tracking-[0.3em] hover:text-fuchsia-300 underline underline-offset-4"
                >
                  Reset Filter Array
                </button>
              </div>
            ) : (
              <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
                {filteredResults.map((result) => (
                  <AnalysisCard key={result.id} result={result} onDelete={deleteResult} />
                ))}
              </div>
            )}
          </div>
        </div>
      </main>

      <footer className="mt-20 py-12 border-t border-purple-900/50 text-center">
        <div className="flex justify-center gap-8 mb-6 opacity-40">
          <Fingerprint className="w-5 h-5 text-purple-500" />
          <Zap className="w-5 h-5 text-purple-500" />
          <BarChart3 className="w-5 h-5 text-purple-500" />
        </div>
        <p className="text-purple-600 text-[10px] font-black uppercase tracking-[0.5em]">
          PYTHENIANS LABO // NEURAL VERIFICATION PROTOCOL // AUTHENTICITY ESTABLISHED 2024
        </p>
      </footer>
    </div>
  );
}
